solution: class Solution {
public:
    int reachNumber(int target) {
        target = abs(target);
        long long k = 0, sum = 0;
        while (sum < target) {
            ++k;
            sum += k;
        }
        while ((sum - target) % 2 != 0) {
            ++k;
            sum += k;
        }
        return static_cast<int>(k);
    }
};
